// Pega o embedding retornado pela OpenAI
const embeddingData = $('HTTP Request: Gerar Embedding do navio').first().json;
const embeddingArray = embeddingData.data?.[0]?.embedding;

if (!embeddingArray || embeddingArray.length === 0) {
  throw new Error('OpenAI não retornou embedding. Verifique a API Key e o campo "input".');
}

// Converte o array para string no formato pgvector
const vectorString = '[' + embeddingArray.join(',') + ']';

// Pega as quantidades do Trigger e converte para int
const trigger = $('Workflow Trigger').first().json;
const qtdAdultos  = parseInt(trigger.qtd_adultos)  || 1;
const qtdCriancas = parseInt(trigger.qtd_criancas) || 0;
const navioPedido = trigger.navio || '';

return [{
  json: {
    vector_string: vectorString,
    qtd_adultos:   qtdAdultos,
    qtd_criancas:  qtdCriancas,
    navio_pedido:  navioPedido,
  }
}];

// ═══════════════════════════════════════════════════════════
// ALGORITMO DE DISTRIBUIÇÃO DE experience resource (Backtracking)
// ═══════════════════════════════════════════════════════════
//
// Estratégia: preencher ao máximo, priorizando experience resource maiores
// Restrição: toda experience resource com criança deve ter >= 1 adulto
// Disponibilidade: consulta dinâmica por navio
// ═══════════════════════════════════════════════════════════

const inputs = $('Code: Extrair vetor e preparar inputs').first().json;
const combRows = $('PostgreSQL: Buscar combinacoes disponiveis').all();

const totalAdultos  = inputs.qtd_adultos;
const totalCriancas = inputs.qtd_criancas;
const totalPessoas  = totalAdultos + totalCriancas;
const MAX_POR_CABINE = 4;

// ── Extrair combinações disponíveis ──
const combinacoes = combRows.map(r => ({
  a:   r.json.qtd_adultos,
  c:   r.json.qtd_criancas,
  cap: r.json.capacidade
}));

// Se nenhuma combinação encontrada, navio provavelmente não existe
if (combinacoes.length === 0) {
  return [{
    json: {
      sucesso: false,
      motivo: `Nenhuma experience resource encontrada para o navio "${inputs.navio_pedido}". Verifique se o nome está correto.`,
      alternativa: null,
      alternativa_descricao: 'Nenhuma alternativa disponível. Encaminhar para atendente.'
    }
  }];
}

// ── Filtrar combinações válidas ──
// Regra 1: se tem criança, precisa de adulto
// Regra 2: ninguém sozinho na experience resource (min 2 pessoas, exceto viajante solo)
const MIN_POR_CABINE = (totalPessoas === 1) ? 1 : 2;

const combValidas = combinacoes.filter(c => {
  // Regra 1: criança precisa de adulto
  if (c.c > 0 && c.a < 1) return false;
  // Regra 2: experience resource com menos de MIN_POR_CABINE pessoas é excluída
  if (c.cap < MIN_POR_CABINE) return false;
  return true;
});
// Ordenar por capacidade DESC (preencher ao máximo)
combValidas.sort((a, b) => b.cap - a.cap);

// ── CASO SIMPLES: cabe em 1 experience resource ──
if (totalPessoas <= MAX_POR_CABINE) {
  const match = combValidas.find(c => c.a === totalAdultos && c.c === totalCriancas);
  if (match) {
    return [{
      json: {
        sucesso: true,
        total_cabines: 1,
        cabine_idx: 1,
        qtd_adultos: totalAdultos,
        qtd_criancas: totalCriancas,
        vector_string: inputs.vector_string,
        navio_pedido: inputs.navio_pedido,
      }
    }];
  }
  // Combinação exata não existe → cai no backtracking
}

// ── BACKTRACKING: encontrar menor número de experience resource ──
let melhorSolucao = null;

function resolver(aRest, cRest, experience resource, prof) {
  if (prof > 10) return; // segurança
  if (aRest === 0 && cRest === 0) {
    if (!melhorSolucao || experience resource.length < melhorSolucao.length) {
      melhorSolucao = experience resource.map(c => ({...c}));
    }
    return;
  }
  if (aRest < 0 || cRest < 0) return;
  if (melhorSolucao && experience resource.length >= melhorSolucao.length) return; // poda

  for (const comb of combValidas) {
    if (comb.a > aRest || comb.c > cRest) continue;
    if (comb.a === 0 && comb.c === 0) continue;

    experience resource.push({ qtd_adultos: comb.a, qtd_criancas: comb.c });
    resolver(aRest - comb.a, cRest - comb.c, experience resource, prof + 1);
    experience resource.pop();
  }
}

resolver(totalAdultos, totalCriancas, [], 0);

if (melhorSolucao) {
  // Retorna N items, um por experience resource (n8n processa cada um nos nós seguintes)
  return melhorSolucao.map((cab, i) => ({
    json: {
      sucesso: true,
      total_cabines: melhorSolucao.length,
      cabine_idx: i + 1,
      qtd_adultos: cab.qtd_adultos,
      qtd_criancas: cab.qtd_criancas,
      vector_string: inputs.vector_string,
      navio_pedido: inputs.navio_pedido,
    }
  }));
}

// ── FALLBACK: não conseguiu encaixar → propor alternativa ──
let alternativa = null;

function resolverAlt(aRest, cRest, experience resource, prof) {
  if (prof > 10) return;
  if (aRest === 0 && cRest === 0) {
    if (!alternativa || experience resource.length < alternativa.length) {
      alternativa = experience resource.map(c => ({...c}));
    }
    return;
  }
  if (aRest < 0 || cRest < 0) return;
  if (alternativa && experience resource.length >= alternativa.length) return;
  for (const comb of combValidas) {
    if (comb.a > aRest || comb.c > cRest) continue;
    if (comb.a === 0 && comb.c === 0) continue;
    experience resource.push({ qtd_adultos: comb.a, qtd_criancas: comb.c });
    resolverAlt(aRest - comb.a, cRest - comb.c, experience resource, prof + 1);
    experience resource.pop();
  }
}

// Tentar variações (reduzir crianças, adicionar adultos)
const tentativas = [];
for (let dA = 0; dA <= 3; dA++) {
  for (let dC = 0; dC >= -totalCriancas; dC--) {
    if (dA === 0 && dC === 0) continue; // já tentamos o original
    tentativas.push([totalAdultos + dA, totalCriancas + dC]);
  }
}
// Tentar reduzir adultos também
for (let dA = -1; dA >= -2; dA--) {
  tentativas.push([totalAdultos + dA, totalCriancas]);
}

for (const [novoA, novoC] of tentativas) {
  if (novoA < 1 || novoC < 0) continue;
  resolverAlt(novoA, novoC, [], 0);
  if (alternativa) break;
}

const altDescricao = alternativa
  ? alternativa.map((c, i) =>
      `experience resource ${i+1}: ${c.qtd_adultos} adulto(s)` +
      (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '')
    ).join('\n')
  : null;

return [{
  json: {
    sucesso: false,
    motivo: `Não foi possível distribuir ${totalAdultos} adulto(s) e ${totalCriancas} criança(s) nas experience resource disponíveis para este navio.`,
    alternativa: alternativa,
    alternativa_descricao: altDescricao || 'Nenhuma alternativa encontrada. Encaminhar para atendente.',
    navio_pedido: inputs.navio_pedido,
    total_adultos_original: totalAdultos,
    total_criancas_original: totalCriancas,
  }
}];

// ═══════════════════════════════════════════════════════════
// VALIDAR SIMILARIDADE E AGREGAR TODOS OS LINKS
// ═══════════════════════════════════════════════════════════
//
// Recebe N items (um por experience resource) vindos do PostgreSQL.
// Valida a similaridade de cada um e monta o resultado final.
// ═══════════════════════════════════════════════════════════

const SIMILARITY_THRESHOLD = 0.44;

const resultadosPG = $('PostgreSQL: Busca vetorial por experience resource').all();
const distribuicao = $('Code: Calcular distribuicao de experience resource').all();

const experience resource = [];
let todasEncontradas = true;
let navioPrincipal = '';

for (let i = 0; i < resultadosPG.length; i++) {
  const res = resultadosPG[i].json;
  const dist = distribuicao[i].json;
  const cabineIdx = dist.cabine_idx;
  navioPrincipal = dist.navio_pedido;

  // Caso 1: sem resultado
  if (!res || !res.link_reserva) {
    todasEncontradas = false;
    experience resource.push({
      cabine_idx: cabineIdx,
      encontrado: false,
      qtd_adultos: dist.qtd_adultos,
      qtd_criancas: dist.qtd_criancas,
      motivo: `Sem link para ${dist.qtd_adultos} adulto(s) e ${dist.qtd_criancas} criança(s).`,
    });
    continue;
  }

  const similarity = parseFloat(res.similarity) || 0;

  // Caso 2: similaridade baixa
  if (similarity < SIMILARITY_THRESHOLD) {
    todasEncontradas = false;
    experience resource.push({
      cabine_idx: cabineIdx,
      encontrado: false,
      qtd_adultos: dist.qtd_adultos,
      qtd_criancas: dist.qtd_criancas,
      motivo: `Navio não reconhecido (similaridade: ${similarity.toFixed(2)}). Match: "${res.navio}".`,
      debug_similarity: similarity,
    });
    continue;
  }

  // Caso 3: sucesso
  experience resource.push({
    cabine_idx: cabineIdx,
    encontrado: true,
    link_reserva: res.link_reserva,
    navio: res.navio,
    qtd_adultos: parseInt(res.qtd_adultos),
    qtd_criancas: parseInt(res.qtd_criancas),
    observacoes: res.observacoes || '',
    similarity: similarity,
  });
}

return [{
  json: {
    todas_encontradas: todasEncontradas,
    total_cabines: experience resource.length,
    navio: navioPrincipal,
    experience resource: experience resource,
  }
}];

// ═══════════════════════════════════════════════════════════
// MONTAR MENSAGEM FINAL (multi-link ou single-link)
// ═══════════════════════════════════════════════════════════

const data = $input.first().json;
const experience resource = data.experience resource || [];
const totalCabines = experience resource.length;
const navio = data.navio || 'este navio';

// ── Calcular totais ──
let totalAdultos = 0;
let totalCriancas = 0;
for (const c of experience resource) {
  totalAdultos += c.qtd_adultos || 0;
  totalCriancas += c.qtd_criancas || 0;
}
const totalPessoas = totalAdultos + totalCriancas;

let msg = '';

if (data.todas_encontradas) {
  // ── SUCESSO TOTAL ──
  if (totalCabines === 1) {
    // Mensagem original (1 experience resource)
    const c = experience resource[0];
    msg = `Aqui está o seu link para garantir a reserva no *${c.navio}* para ` +
      `${c.qtd_adultos} adulto(s)` +
      (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '') +
      `:\n\n🔗 ${c.link_reserva}\n\n` +
      (c.observacoes ? `⚠️ _${c.observacoes}_\n\n` : '');
  } else {
    // Mensagem multi-experience resource
    msg = `Seu grupo de ${totalPessoas} pessoas precisa de *${totalCabines} experience resource* no *${experience resource[0].navio}*:\n\n`;

    for (const c of experience resource) {
      const pessoas = c.qtd_adultos + ' adulto(s)' +
        (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '');
      msg += `🔗 *experience resource ${c.cabine_idx}* (${pessoas}):\n${c.link_reserva}\n`;
      if (c.observacoes) {
        msg += `⚠️ _${c.observacoes}_\n`;
      }
      msg += '\n';
    }

    msg += `📋 _Cada link corresponde a uma experience resource separada. Complete todas as reservas para garantir seu grupo!_\n\n`;
  }
} else {
  // ── SUCESSO PARCIAL ──
  const encontradas = experience resource.filter(c => c.encontrado);
  const naoEncontradas = experience resource.filter(c => !c.encontrado);

  if (encontradas.length === 0) {
    msg = `Não encontrei links de reserva disponíveis para o *${navio}* com essa configuração de grupo. 😔\n\n` +
      `Vou encaminhar para um especialista que pode ajudar com outras opções! 🙏`;
  } else {
    msg = `Encontrei parte dos links para o seu grupo:\n\n`;
    for (const c of encontradas) {
      const pessoas = c.qtd_adultos + ' adulto(s)' +
        (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '');
      msg += `✅ *experience resource ${c.cabine_idx}* (${pessoas}):\n${c.link_reserva}\n\n`;
    }
    for (const c of naoEncontradas) {
      const pessoas = c.qtd_adultos + ' adulto(s)' +
        (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '');
      msg += `❌ *experience resource ${c.cabine_idx}* (${pessoas}): link não disponível\n`;
    }
    msg += `\nVou encaminhar para um especialista resolver as experience resource pendentes. Pode aguardar um momento? 🙏`;
  }
}

return [{ json: { mensagem: msg } }];

// ═══════════════════════════════════════════════════════════
// MONTAR MENSAGEM COM PROPOSTA ALTERNATIVA
// ═══════════════════════════════════════════════════════════

const data = $input.first().json;
const navio = data.navio_pedido || 'este navio';
const adultos = data.total_adultos_original || 0;
const criancas = data.total_criancas_original || 0;

let msg = '';

if (data.alternativa && data.alternativa.length > 0) {
  msg = `Entendi que seu grupo tem ${adultos} adulto(s)`;
  if (criancas > 0) msg += ` e ${criancas} criança(s)`;
  msg += ` 🤔\n\n`;
  msg += `Com as experience resource disponíveis para o *${navio}*, não consegui montar a distribuição exata. `;
  msg += `Mas tenho uma sugestão:\n\n`;
  msg += `📋 *Proposta alternativa:*\n`;

  for (const c of data.alternativa) {
    const pessoas = c.qtd_adultos + ' adulto(s)' +
      (c.qtd_criancas > 0 ? ` e ${c.qtd_criancas} criança(s)` : '');
    msg += `  • experience resource: ${pessoas}\n`;
  }

  msg += `\nEssa distribuição funcionaria para vocês? 😊\n\n`;
  msg += `_(Caso prefira, posso chamar um especialista para ajudar com outras opções!)_`;
} else {
  msg = `Entendi que seu grupo tem ${adultos} adulto(s)`;
  if (criancas > 0) msg += ` e ${criancas} criança(s)`;
  msg += `.\n\n`;
  msg += `Infelizmente não consegui encontrar uma combinação de experience resource que atenda seu grupo no *${navio}*. 😔\n\n`;
  msg += `Vou encaminhar para um especialista que pode montar uma proposta personalizada! 🙏`;
}

return [{ json: { mensagem: msg } }];
